    function displayErrMsg(toDisplay, fieldId) {
        error = true;
        var field = $("#" + fieldId);
        field.attr('aria-describedby', toDisplay);
        field.attr('aria-invalid', 'true');
        $("#" + toDisplay).show();
    }

    function hideAllErrors() {
        $(".error").hide();
    }

    function hideError(toHide, fieldId) {
        var field = $("#" + fieldId);
        field.removeAttr('aria-describedby');
        field.removeAttr('aria-invalid', 'true');
        $("#" + toHide).hide();
    }

    // First name
    function validateField1() {
        re = /^[a-zA-Z]+(([',. -][a-zA-Z ])?[a-zA-Z]*)*$/;
        error = false;

        hideError('Field1-err1', 'Field1');
        hideError('Field1-err2', 'Field1');

        if (document.contactForm.Field1.value == '') {
            displayErrMsg('Field1-err1', 'Field1');
        } else if (!re.test(document.contactForm.Field1.value)) {
            displayErrMsg('Field1-err2', 'Field1');
        } else {
            $("#Field1-err1").hide();
            $("#Field1-err2").hide();
        }

        return error;
    }

    // Phone number
    function validateField2() {
        re = /^(?:(?:\+?1\s*(?:[.-]\s*)?)?(?:\(\s*([2-9]1[02-9]|[2-9][02-8]1|[2-9][02-8][02-9])\s*\)|([2-9]1[02-9]|[2-9][02-8]1|[2-9][02-8][02-9]))\s*(?:[.-]\s*)?)?([2-9]1[02-9]|[2-9][02-9]1|[2-9][02-9]{2})\s*(?:[.-]\s*)?([0-9]{4})(?:\s*\s*(\d+))?$/;

        error = false;

        hideError('Field2-err1', 'Field2');
        hideError('Field2-err2', 'Field2');

        if (document.contactForm.Field2.value == '') {
            displayErrMsg('Field2-err1', 'Field2');
        } else if (!re.test(document.contactForm.Field2.value)) {
            displayErrMsg('Field2-err2', 'Field2');

        } else {
            $("#Field2-err1").hide();
            $("#Field2-err2").hide();
        }

        return error;
    }

    //E-mail
    function validateField3() {
        re = /^(([^<>()\[\]\\.,;:\s@"]+(\.[^<>()\[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/;
        error = false;

        hideError('Field3-err1', 'Field3');
        hideError('Field3-err2', 'Field3');

        if (document.contactForm.Field3.value == '') {
            displayErrMsg('Field3-err1', 'Field3');
        } else if (!re.test(document.contactForm.Field3.value)) {
            displayErrMsg('Field3-err2', 'Field3');

        } else {
            $("#Field3-err1").hide();
            $("#Field3-err2").hide();
        }

        return error;
    }


    //Zip Code
    function validateField4() {
        re = /^[a-zA-Z0-0!@#\$%\^\&*\)\(+=._-]+$/;
        lengthMax = /^\d{5}?$/;
        error = false;

        hideError('Field4-err1', 'Field4');
        hideError('Field4-err2', 'Field4');
        hideError('Field4-err3', 'Field4');

        if (document.contactForm.Field4.value == '') {
            displayErrMsg('Field4-err1', 'Field4');
        } else if (re.test(document.contactForm.Field4.value)) {
            displayErrMsg('Field4-err2', 'Field4');
        } else if (!lengthMax.test(document.contactForm.Field4.value)) {
            displayErrMsg('Field4-err3', 'Field4');

        }
        return error;
    }

    $(document).ready(function () {
        $("#contactFormSubmitButton").click(function (event) {
            error1 = validateField1();
            error2 = validateField2();
            error3 = validateField3();
            error4 = validateField4();

            var error = error1 || error2 || error3 || error4;

            if (!error) {
                var language = (window.location.href.indexOf('/fr/') > -1) ? "-fr" : "";
                var requestData = $('#share-form').serializeObject();
                var confirmationPage = requestData.form.collectedData.confirmPage;
                $.ajax({
                    url: 'https://www.cibconline.cibc.com/ebm-forms/api/v2/json/forms',
                    async: true,
                    cache: false,
                    type: 'POST',
                    dataType: 'json',
                    data: JSON.stringify(requestData, null, ' '),
                    headers: {
                        'accept': 'application/vnd.api+json',
                        'brand': 'cibc',
                        'content-type': 'application/vnd.api+json'
                    },
                    success: function () {
                        window.location = 'https://us.cibc.com' + confirmationPage;
                    },
                    error: function () {
                        window.location = "https://us.cibc.com/en/error.html";
                    }
                });
            } else {
                $('[aria-invalid="true"]').eq(0).focus();
            }
        });
    });


